  1	import React, { FC, useCallback } from 'react';
  2	import { useNavigate } from 'react-router-dom-v5-compat';
  3	
  4	import { useWizardSourceAvailable } from '@catalog/utils/useWizardSourceAvailable';
  5	import VirtualMachineModel from '@kubevirt-ui/kubevirt-api/console/models/VirtualMachineModel';
  6	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
  7	import {
  8	  RUNSTRATEGY_ALWAYS,
  9	  RUNSTRATEGY_HALTED,
 10	  RUNSTRATEGY_RERUNONFAILURE,
 11	} from '@kubevirt-utils/constants/constants';
 12	import { logTemplateFlowEvent } from '@kubevirt-utils/extensions/telemetry/telemetry';
 13	import {
 14	  CANCEL_CUSTOMIZE_VM_BUTTON_CLICKED,
 15	  CUSTOMIZE_PAGE_CREATE_VM_BUTTON_CLICKED,
 16	} from '@kubevirt-utils/extensions/telemetry/utils/constants';
 17	import { DISABLED_GUEST_SYSTEM_LOGS_ACCESS } from '@kubevirt-utils/hooks/useFeatures/constants';
 18	import { useFeatures } from '@kubevirt-utils/hooks/useFeatures/useFeatures';
 19	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 20	import { getName, getResourceUrl } from '@kubevirt-utils/resources/shared';
 21	import useNamespaceUDN from '@kubevirt-utils/resources/udn/hooks/useNamespaceUDN';
 22	import { createHeadlessService } from '@kubevirt-utils/utils/headless-service';
 23	import {
 24	  Alert,
 25	  Button,
 26	  Checkbox,
 27	  Split,
 28	  SplitItem,
 29	  Stack,
 30	  StackItem,
 31	} from '@patternfly/react-core';
 32	
 33	import { useWizardVmCreate } from '../../utils/useWizardVmCreate';
 34	import { clearSessionStorageVM, useWizardVMContext } from '../../utils/WizardVMContext';
 35	
 36	import { WizardNoBootModal } from './WizardNoBootModal';
 37	
 38	export const WizardFooter: FC<{ namespace: string }> = ({ namespace }) => {
 39	  const navigate = useNavigate();
 40	  const { t } = useKubevirtTranslation();
 41	  const [isUDNManagedNamespace] = useNamespaceUDN(namespace);
 42	  const { disableVmCreate, loaded: vmContextLoaded, updateVM, vm } = useWizardVMContext();
 43	  const { isBootSourceAvailable, loaded: bootSourceLoaded } = useWizardSourceAvailable();
 44	  const { createVM, error, loaded: vmCreateLoaded } = useWizardVmCreate();
 45	  const { createModal } = useModal();
 46	  const { featureEnabled: isDisableGuestSystemAccessLog } = useFeatures(
 47	    DISABLED_GUEST_SYSTEM_LOGS_ACCESS,
 48	  );
 49	
 50	  const onCreate = async () =>
 51	    createVM({
 52	      isDisableGuestSystemAccessLog,
 53	      onFullfilled: (createdVM) => {
 54	        if (!isUDNManagedNamespace) createHeadlessService(createdVM);
 55	
 56	        clearSessionStorageVM();
 57	        navigate(getResourceUrl({ model: VirtualMachineModel, resource: createdVM }));
 58	      },
 59	    });
 60	
 61	  const onSubmit = () => {
 62	    logTemplateFlowEvent(CUSTOMIZE_PAGE_CREATE_VM_BUTTON_CLICKED, null, { vmName: getName(vm) });
 63	
 64	    if (isBootSourceAvailable) {
 65	      return onCreate();
 66	    }
 67	
 68	    createModal(({ isOpen, onClose }) => (
 69	      <WizardNoBootModal
 70	        isOpen={isOpen}
 71	        namespace={namespace}
 72	        onClose={onClose}
 73	        onSubmit={onCreate}
 74	      />
 75	    ));
 76	  };
 77	
 78	  const loaded = vmContextLoaded && vmCreateLoaded && bootSourceLoaded;
 79	
 80	  const onChangeStartVM = useCallback(
 81	    (checked: boolean) => {
 82	      updateVM((draftVM) => {
 83	        delete draftVM.spec.running;
 84	        draftVM.spec.runStrategy = checked ? RUNSTRATEGY_ALWAYS : RUNSTRATEGY_HALTED;
 85	      });
 86	    },
 87	    [updateVM],
 88	  );
 89	
 90	  const runStrategy = vm?.spec?.runStrategy;
 91	
 92	  return (
 93	    <footer className="vm-wizard-footer">
 94	      <Stack hasGutter>
 95	        <StackItem>
 96	          <Checkbox
 97	            isChecked={
 98	              vm?.spec?.running ||
 99	              runStrategy === RUNSTRATEGY_ALWAYS ||
100	              runStrategy === RUNSTRATEGY_RERUNONFAILURE
101	            }
102	            label={
103	              runStrategy
104	                ? t('Start this VirtualMachine after creation ({{runStrategy}})', {
105	                    runStrategy,
106	                  })
107	                : t('Start this VirtualMachine after creation')
108	            }
109	            id="start-after-create-checkbox"
110	            isDisabled={!loaded || disableVmCreate || !isBootSourceAvailable}
111	            onChange={(_, checked: boolean) => onChangeStartVM(checked)}
112	          />
113	        </StackItem>
114	        <StackItem />
115	        {error && (
116	          <StackItem>
117	            <Alert isInline title={t('Create VirtualMachine error')} variant="danger">
118	              {error.message}
119	            </Alert>
120	          </StackItem>
121	        )}
122	        <div data-test-id="create-virtual-machine">
123	          <Split hasGutter>
124	            <SplitItem>
125	              <Button
126	                isDisabled={!loaded || disableVmCreate}
127	                isLoading={!vmCreateLoaded}
128	                onClick={onSubmit}
129	                variant="primary"
130	              >
131	                {t('Create VirtualMachine')}
132	              </Button>
133	            </SplitItem>
134	            <SplitItem>
135	              <Button
136	                onClick={() => {
137	                  logTemplateFlowEvent(CANCEL_CUSTOMIZE_VM_BUTTON_CLICKED, null, {
138	                    vmName: getName(vm),
139	                  });
140	                  if (confirm(t('Are you sure you want to cancel?'))) {
141	                    clearSessionStorageVM();
142	                    navigate(`/k8s/ns/${namespace}/catalog/template`);
143	                  }
144	                }}
145	                variant="link"
146	              >
147	                {t('Cancel')}
148	              </Button>
149	            </SplitItem>
150	          </Split>
151	        </div>
152	      </Stack>
153	    </footer>
154	  );
155	};

